#!/usr/bin/env bash
# Oracle solution: applies the gold diff from PR angular/angular#67966.
# The patch is base64-encoded inline so trailing whitespace on empty
# context lines (which git apply requires) cannot be silently stripped by
# editors / file-write tools.
set -euo pipefail

cd /workspace/angular

if grep -qF 'npx ng generate guard <guard-name>' \
        skills/dev-skills/angular-new-app/SKILL.md; then
    echo "Already applied; skipping."
    exit 0
fi

PATCH_B64=''

PATCH_TMP="$(mktemp)"
echo "$PATCH_B64" | base64 -d > "$PATCH_TMP"

git apply --whitespace=nowarn "$PATCH_TMP"
rm -f "$PATCH_TMP"

echo "Applied gold patch."
